import{_ as a,o as s,c as t,a6 as o}from"./chunks/framework.DtxWasON.js";const h=JSON.parse('{"title":"Fees and Gas","description":"","frontmatter":{},"headers":[],"relativePath":"mainchain/introduction/fees-and-gas.md","filePath":"mainchain/introduction/fees-and-gas.md"}'),i={name:"mainchain/introduction/fees-and-gas.md"};function n(d,e,c,l,r,p){return s(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="fees-and-gas" tabindex="-1">Fees and Gas <a class="header-anchor" href="#fees-and-gas" aria-label="Permalink to &quot;Fees and Gas&quot;">​</a></h1><p>Transactions consume gas, and the sender must pay a fee in order for the transaction be processed by the validator nodes. The fee is calculated from the amount of gas a Tx will consume multiplied by the gas price.</p><div class="tip custom-block"><p class="custom-block-title">NOTE</p><p>The gas price for a transaction is set by the sender of the Tx, but each validator will have set their own <code>minimum-gas-prices</code> value, and will not process transactions that do not meet this minimum requirement.</p></div><p>Fees are paid in <code>nund</code>, and may be either set or calculated depending on which flags are passed to the <code>und</code> command.</p><div class="tip custom-block"><p class="custom-block-title">NOTE</p><p>only <code>--fees</code> or <code>--gas-prices</code> may be used - not both at the same time.</p></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><code>--gas-prices</code> can be used along with the <code>--gas=auto</code> and <code>--gas-adjustment</code> flags to estimate the gas requirement and automatically calculate the Tx fees.</p></div><h2 id="example-1-setting-fees" tabindex="-1">Example 1: setting --fees <a class="header-anchor" href="#example-1-setting-fees" aria-label="Permalink to &quot;Example 1: setting --fees&quot;">​</a></h2><p>In this example, we&#39;re manually setting the fee for a standard <code>send</code> transaction. The validator has a <code>minimum-gas-prices</code> of <code>25.0nund</code>. We&#39;ll set the <code>--fee</code> to 2000000nund. For the purposes of simpler calculations, we&#39;ll assume the amount of <strong>gas</strong> consumed for this <code>send</code> transaction, including a small <code>--memo</code> will be around 65000.</p><div class="tip custom-block"><p class="custom-block-title">NOTE</p><p>gas is defined on the chain as a flat cost per byte for a Tx, e.g. 10 gas per byte. The total size of our Tx will be around 6500 bytes, and therefore the gas consumed by the Tx will be 6500 * 10 = 65000.</p></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>und tx send [from] [to] 123456nund --memo=&quot;some und from me to you&quot; --fees=2000000nund</span></span></code></pre></div><p>In this instance, the <code>gas-price</code> is implied as approximately 30.77nund (fee / gas: 2000000 / 65000), so the Validator will accept the Tx and include it in the block, since 30.77nund &gt; 25.0nund.</p><p>If we had set the <code>--fees</code> to 1000000, it would not have been processed by the Validator (1000000 / 65000 = 15.38nund).</p><div class="tip custom-block"><p class="custom-block-title">NOTE</p><p>the Tx with lower fees may remain the Tx pool until a validator with lower <code>minimum-gas-prices</code> picks it up and proposes the block.</p></div><h2 id="example-2-setting-gas-and-gas-prices" tabindex="-1">Example 2: setting --gas and --gas-prices <a class="header-anchor" href="#example-2-setting-gas-and-gas-prices" aria-label="Permalink to &quot;Example 2: setting --gas and --gas-prices&quot;">​</a></h2><p>In this example, we&#39;ll set our own <code>--gas-prices</code>, and ask <code>und</code> to estimate the amount of gas the Tx will consume based on the Tx input by passing the <code>--gas=auto</code> flag. We can also use the <code>--gas-adjustment</code> flag to increase/decrease this gas estimate. We&#39;ll assume again that the calculated estimate will be around 65000 gas:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>und tx send from to 123456nund --memo=&quot;some und from me to you&quot; --gas=auto --gas-prices=25.0nund</span></span></code></pre></div><p>In this example, the Tx <strong>fee</strong> will be calculated and included in the transaction for us. The fee will be around 1625000nund (<code>gas * gas-prices</code>: 65000 * 25.0). Since we have set <code>gas-prices</code> already to 25.0 (and assuming the gas estimate is also correct), this Tx will be processed by the validator.</p><div class="tip custom-block"><p class="custom-block-title">NOTE</p><p>Adding the <code>--gas-adjustment</code> flag, for example <code>--gas-adjustment=1.5</code>, will increase the gas estimate and therefore the fee, but will increase the chances of the Tx being processed.</p></div><p>Validators will prioritise Txs with higher <code>gas-prices</code>, so it is worth setting higher prices to ensure your Tx is processed.</p>',19)])])}const m=a(i,[["render",n]]);export{h as __pageData,m as default};
